.darma-loader-darma-custom-689 {
  color: var(--loader-color, #f59e0b);
  --loader-secondary-color: var(--loader-secondary-color, #fde68a);
  --loader-bg: var(--loader-bg, #ffffff);
width: 45px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(currentColor 0 0);
background: var(--c), var(--c), var(--c);
animation:
darma-loader-darma-custom-689-l15-1 1s infinite,
